using System;
using System.IO;
using System.Runtime.Serialization.Formatters.Binary;

public class SessionManager
{
    private string _sessionPath = "sessions";
    private BinaryFormatter _formatter = new BinaryFormatter();

    public void SaveSession(int userId, object session)
    {
        if (!Directory.Exists(_sessionPath))
            Directory.CreateDirectory(_sessionPath);

        using (FileStream file = File.Create(Path.Combine(_sessionPath, $"{userId}.dat")))
        {
            _formatter.Serialize(file, session);
        }
    }

    public object LoadSession(int userId)
